// // This module implements a 2-bit register that updates its output 'q' on every clock edge regardless of the enable signal 'en'
module top_module (
    input wire [1:0] d,
    input wire clk,
    input wire en,
    output reg [1:0] q
);

    always @(posedge clk) begin
        if (en)
            q <= d;
    end

endmodule
